// 初始化调度器 — 使用 SpinNoIrqLock 实现多核安全 + 关中断保护
lazy_static! {
    static ref SCHEDULER: SpinNoIrqLock<Scheduler> = SpinNoIrqLock::new(Scheduler::new());
}

/// 添加新任务到就绪队列
/// 锁生命周期仅局限于 push_back 操作，快进快出。
pub fn add_task(task: Arc<Task>) {
    debug_assert!(task.is_ready());
    SCHEDULER.lock().add(task);
}

/// 从就绪队列中取出队首任务
/// 锁生命周期仅局限于 pop_front 操作，快进快出。
pub fn fetch_task() -> Option<Arc<Task>> {
    SCHEDULER.lock().fetch()
}

/// 从就绪队列中移除指定任务
/// 锁生命周期仅局限于 remove 操作，快进快出。
pub fn remove_task(tid: Tid) {
    SCHEDULER.lock().remove(tid);
}

/// 查看调度器中任务数量
/// 锁生命周期仅局限于 len 查询，快进快出。
pub fn get_scheduler_len() -> usize {
    SCHEDULER.lock().len()
}

/// 打印调度器中任务信息
/// 先在临界区内收集元数据到临时 Vec 中，离开锁后再进行串口 I/O（println），
/// 避免在持锁期间调用耗时的日志打印，防止死锁和长时间关中断。
pub fn dump_scheduler() {
    // 临界区：仅收集需要打印的元数据
    let tasks_info: alloc::vec::Vec<(Tid, usize)> = {
        let scheduler = SCHEDULER.lock();
        scheduler
            .ready_queue
            .iter()
            .map(|task| (task.tid(), Arc::strong_count(task)))
            .collect()
    };
    // 锁已释放，中断已恢复，安全进行 I/O

    println!("task {} is running", current_task().tid());
    println!("**************************** dump scheduler ****************************");
    for (tid, strong_count) in &tasks_info {
        println!(
            "task {} in scheduler \tstrong count: {}",
            tid, strong_count
        );
    }
    println!("**************************** dump scheduler ****************************");
    dump_wait_queue();
}

// 由caller保证原任务的状态切换
// 不能从自己切换到自己, 否则会死Idle循环
// used by sys_exit
//
// 关键约束：绝对不允许持有 SCHEDULER 锁进入 __switch 上下文切换。
// fetch_task() 内部已完成 锁→取出→解锁 的原子操作，
// __switch 始终在锁外执行。
#[no_mangle]
pub fn schedule() {
    // 1. 切换内核栈
    // 2. 切换Processor的current
    // 3. 切换tp(在__switch中完成)
    // 4. 切换memory set(在__switch中完成)

    // 获得下一个任务的内核栈
    // 可以保证`Ready`的任务`Task`中的内核栈与实际运行的sp保持一致
    log::trace!("[schedule]");
    // fetch_task() 内部：SCHEDULER.lock() → fetch → drop(lock)
    // 锁在 fetch_task 返回前已释放，__switch 在锁外执行
    if let Some(next_task) = fetch_task() {
        let next_task_kernel_stack = next_task.kstack();
        {
            log::debug!(
                "**********************************  task {} end **********************************",
                current_task().tid()
            );
            log::debug!(
                "**********************************  task {} start **********************************",
                next_task.tid()
            );
            // check_task_context_in_kernel_stack(next_task_kernel_stack);
            // 切换Processor的current
            crate::task::processor::PROCESSOR
                .write()
                .switch_to(next_task);
        }
        unsafe {
            switch::__switch(next_task_kernel_stack);
        }
    } else {
        // 如果没有下一个任务, 则busyloop等待计时器超时
        loop {
            log::trace!("[schedule] no next task, waiting for timeout");
            // fetch_task() 内部已完成锁的获取与释放
            if let Some(next_task) = fetch_task() {
                let next_task_kernel_stack = next_task.kstack();
                {
                    log::debug!(
                        "**********************************  task {} end **********************************",
                        current_task().tid()
                    );
                    log::debug!(
                        "**********************************  task {} start **********************************",
                        next_task.tid()
                    );
                    // check_task_context_in_kernel_stack(next_task_kernel_stack);
                    // 切换Processor的current
                    crate::task::processor::PROCESSOR
                        .write()
                        .switch_to(next_task);
                }
                unsafe {
                    switch::__switch(next_task_kernel_stack);
                }
                break;
            }
            if !handle_timeout().is_empty() {
                // 计时器超时
                if let Some(next_task) = fetch_task() {
                    let next_task_kernel_stack = next_task.kstack();
                    {
                        log::debug!(
                            "**********************************  task {} end **********************************",
                            current_task().tid()
                        );
                        log::debug!(
                            "**********************************  task {} start **********************************",
                            next_task.tid()
                        );
                        if current_task().tid() == next_task.tid() {
                            // 不能从自己切换到自己
                            break;
                        }
                        // check_task_context_in_kernel_stack(next_task_kernel_stack);
                        // 切换Processor的current
                        crate::task::processor::PROCESSOR
                            .write()
                            .switch_to(next_task);
                    }
                    unsafe {
                        switch::__switch(next_task_kernel_stack);
                    }
                    break;
                } else {
                    // 计时器超时, 但是没有就绪任务, 继续执行当前任务
                    break;
                }
            }
        }
    }
}

