// Todo: 为可中断的任务的支持

// 将当前任务加入到basic队列并阻塞
// 返回值：0：正常被唤醒； -1：被中断唤醒
pub fn wait() -> isize {
    log::trace!("[wait]");
    let task = current_task();
    task.set_interruptable();
    WAIT_MANAGER.add(task);
    log::warn!("[wait] task{} block", current_task().tid());
    schedule(); // 调度其他任务
    let task = current_task();
    if task.is_interrupted() {
        task.set_uninterruptable();
        return -1;
    }
    return 0;
}

