        trap_cx.set_tp(tls_ptr as usize);
        save_trap_context(&new_task, trap_cx);
    }
    add_task(new_task);
    if flags.contains(CloneFlags::CLONE_VFORK) {
        log::warn!("[sys_clone] handle CLONE_VFORK");
        // vfork的特殊处理, 需要阻塞父进程直到子进程调用execve或exit
        wait();
    }
    drop(task);
    // yield_current_task();
    Ok(new_task_tid)
}

