                    .areas
                    .range(..old_end_vpn)
                    .filter_map(|(_, area)| {
                        if area.vpn_range.is_intersect_with(&remove_range)
                            && area.map_type == MapType::Heap
                        {
                            // 删除堆区域
                            log::info!(
                                "[sys_brk] remove area: {:?}, vpn_range: {:?}",
                                remove_range,
                                area.vpn_range
                            );
                            Some(area.vpn_range.get_start())
                        } else {
