}

impl FutexQ {
    /// Create a new futex queue
    pub fn new(key: FutexKey, task: Arc<Task>, bitset: u32) -> Self {
        Self {
            key,
            task: Arc::downgrade(&task),
            bitset,
        }
    }
    /// check if the futex queues matches the key
    pub fn match_key(&self, key: &FutexKey) -> bool {
        self.key == *key
    }
}

