pub fn sys_sysinfo(info: *mut SysInfo) -> SyscallRet {
    if info.is_null() {
        return Err(Errno::EFAULT);
    }
    let data = SysInfo {
        uptime: (crate::arch::timer::get_time_ms() / 1000) as isize,
        loads: [0; 3],
        totalram: 512 * 1024 * 1024,
        freeram: 256 * 1024 * 1024,
        sharedram: 0,
        bufferram: 0,
        totalswap: 0,
        freeswap: 0,
        procs: 1,
        pad: 0,
        totalhigh: 0,
        freehigh: 0,
        mem_unit: 1,
        _f: [],
    };
    copy_to_user(info, &data, 1)?;
    Ok(0)
}

